  // === CLOAKS & ROBES ===
  'Cloak of the manta ray': { nameEN: 'Cloak of the Manta Ray', nameIT: 'Mantello della Manta', descEN: 'While wearing this cloak with its hood up, you can breathe underwater and have a swimming speed of 60 feet.', descIT: 'Mentre indossi questo mantello col cappuccio alzato, puoi respirare sott\'acqua e hai una velocità di nuoto di 18 metri.', rarity: 'uncommon' },
