  'Cloak of invisibility': { nameEN: 'Cloak of Invisibility', nameIT: 'Mantello dell\'Invisibilità', descEN: 'While wearing this cloak, you can pull its hood over your head to become invisible.', descIT: 'Mentre indossi questo mantello, puoi tirare il cappuccio sopra la testa per diventare invisibile.', rarity: 'legendary' },
