  'Robe of scintillating colors': { nameEN: 'Robe of Scintillating Colors', nameIT: 'Veste dei Colori Scintillanti', descEN: 'This robe has 3 charges. You can use them to dazzle and stun enemies.', descIT: 'Questa veste ha 3 cariche. Puoi usarle per abbagliare e stordire i nemici.', rarity: 'very rare' },
  'Robe of stars': { nameEN: 'Robe of Stars', nameIT: 'Veste delle Stelle', descEN: 'This robe lets you step into the Astral Plane and cast Magic Missile.', descIT: 'Questa veste ti permette di entrare nel Piano Astrale e lanciare Dardo Incantato.', rarity: 'very rare' },
