// Build case-insensitive + nameEN lookup caches
const lookupCache: Record<string, MagicItemData> = {};
const nameENCache: Record<string, MagicItemData> = {};
for (const key of Object.keys(magicItemsDB)) {
  if (key.startsWith('_alt_') || key.startsWith('x_')) continue;
  const item = magicItemsDB[key];
  lookupCache[key.toLowerCase()] = item;
  nameENCache[item.nameEN.toLowerCase()] = item;
  // Also index by nameIT for reverse lookups
  if (item.nameIT) nameENCache[item.nameIT.toLowerCase()] = item;
}

function findItem(name: string): MagicItemData | undefined {
  // 1. Direct match
  if (magicItemsDB[name]) return magicItemsDB[name];
  // 2. Case-insensitive key match
  const lower = name.toLowerCase();
  if (lookupCache[lower]) return lookupCache[lower];
  // 3. Match by nameEN
  if (nameENCache[lower]) return nameENCache[lower];
  // 4. Strip parenthetical variations: "Weapon, +1" → "weapon"
  const base = lower.replace(/\s*\(.*\)\s*$/, '').replace(/,\s*\+\d+$/, '').trim();
  if (lookupCache[base]) return lookupCache[base];
  if (nameENCache[base]) return nameENCache[base];
  // 5. Try with/without comma: "Armor +1" ↔ "Armor, +1"
  const withComma = lower.replace(/(\w)\s+\+(\d)/, '$1, +$2');
  if (lookupCache[withComma]) return lookupCache[withComma];
  const withoutComma = lower.replace(/,\s*\+/, ' +');
  if (lookupCache[withoutComma]) return lookupCache[withoutComma];
  // 6. Partial contains search (last resort for long compound names)
  for (const key of Object.keys(lookupCache)) {
    if (key.startsWith('_') || key.startsWith('x_')) continue;
    if (lower.includes(key) || key.includes(lower)) {
      if (Math.abs(key.length - lower.length) < 15) return lookupCache[key];
    }
  }
  return undefined;
}

export function getMagicItemData(name: string): MagicItemData | undefined {
  return findItem(name);
}

export function getItemName(name: string, lang: 'en' | 'it'): string {
  const data = findItem(name);
  if (!data) return name;
  return lang === 'it' ? data.nameIT : data.nameEN;
}

export function getItemDescription(name: string, lang: 'en' | 'it'): string {
  const data = findItem(name);
  if (!data) return lang === 'it' ? 'Descrizione non disponibile.' : 'Description not available.';
  return lang === 'it' ? (data.descIT || data.descEN) : data.descEN;
}

export default magicItemsDB;
